errorComponents.js:
const radia = document.querySelectorAll(
  '#edit-vstup_alergeny_ucastnika-' + idUcastnika + ' input[type="radio"]'
);

radia.forEach(function(r) {
  if (r.dataset.syncBound === '1') return;
  r.dataset.syncBound = '1';

  r.addEventListener('change', function() {
    r.dispatchEvent(new Event('input', { bubbles: true }));
  });
});

const vybrane = Array.from(radia).find(function(r) {
  return r.checked;
});

if (vybrane) {
  vybrane.dispatchEvent(new Event('input', { bubbles: true }));
}

